var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"…어쩌죠? 소냐가 숨을 안 쉬는 것 같은데요?!","JPN":"……どうしましょう？　ソーニャ、息していないみたいですけど！？","ENG":"...What do we do? I don't think Sonya's breathing!","TWN":"怎麼辦？索妮雅好像沒呼吸咧？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"정 걱정되면 인공호흡이라도 해보지 그래?","JPN":"そんなに心配なら、人工呼吸でもしてみたらどうだ？","ENG":"If you're that worried, why don't you give her mouth-to-mouth?","TWN":"如果你真的很擔心，不如試試人工呼吸？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"으에엣, 괜찮을까요? 한 번도 해본 적 없는데…!","JPN":"えええっ？　大丈夫でしょうか？　一度もやったことないのに……！","ENG":"Ehh?! Is that necessary? I've never done it before...!","TWN":"什麼？真的嗎？我從來沒做過…！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그, 그럼 들어갑니다!","JPN":"じゃ、じゃあ、いきますわ！","ENG":"Th-then! Here it goes!","TWN":"那…那我要來囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐-읍!","JPN":"ふーうっ！","ENG":"Hmmph!","TWN":"吸氣！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"푸웃…!","JPN":"ぷはっ……！","ENG":"Pfft...!","TWN":"噗…！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC_02"},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"꺄얏-!","JPN":"きゃあー！","ENG":"Kyaa!","TWN":"啊啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"콜록- 콜록-","JPN":"ゲホッ！　ゲホッ！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"정말- 소냐도 참-","JPN":"もうー！　ソーニャったら……","ENG":"Sonya, seriously?","TWN":"索妮雅你真是的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"마우스 투 마우스가 아무리 싫어도 말이죠. 입으로 동전을 쏘면 어떡해요?","JPN":"いくらマウス・トゥー・マウスが嫌だからって。口からコインを飛ばすなんてどういうつもりですか！","ENG":"No matter how much you hate mouth-to-mouth, you shouldn't shoot coins out of your mouth like that.","TWN":"就算你討厭嘴對嘴，也不能從嘴裡發射硬幣吧？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"콜록- 미안. 그게 내 기도를 막고 있어서.","JPN":"ゲホッ、悪い。それがあたしの気道を塞いでた。","ENG":"*Cough!* Sorry. That's the thing that was blocking my airway.","TWN":"咳咳，抱歉，它堵住我的呼吸道。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"뭐, 어쨌든 무사해서 다행이네요!","JPN":"まあ、とにかく無事で良かったですわ！","ENG":"Well, at least you're okay now!","TWN":"算了啦，你沒事就好！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"어떻게 된 거야? 여긴 어디고?","JPN":"どうなってる？　ここはどこだ？","ENG":"What happened? Where am I?","TWN":"剛才發生什麼事？這裡是哪？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"몰라요. 저도 방금 깨어났거든요.","JPN":"わかりません。私もついさっき目を覚ましたので。","ENG":"I don't know either. I just woke up right before you did.","TWN":"不知道，我也才剛醒。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L25_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"다른 사람들도 마찬가지고요.","JPN":"他の人たちも同じです。","ENG":"The same goes for the others.","TWN":"其他人也一樣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"다른 사람들…?","JPN":"他の人たち……？","ENG":"The others...?","TWN":"其他人…？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우엑-! 해조류를 너무 많이 삼켰어.","JPN":"うげーっ！　海藻を飲み込みすぎた。","ENG":"Blech! I swallowed too much seaweed.","TWN":"噁！我吃到好多海藻。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L29_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"좀 전의 그 파도는 대체 뭐였던 거야?","JPN":"さっきのあの波、いったい何だったんだ？","ENG":"What was that wave just now anyway?","TWN":"剛才的海浪是怎麼回事？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L30_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"머리가 깨질 것 같아.","JPN":"頭が割れそうだ。","ENG":"I feel like my head's gonna split.","TWN":"我現在頭痛欲裂。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"이봐! 여기도 사람이 있어! 좀 도와줘!","JPN":"おい！　こっちにも人がいるぞ！　ちょっと手伝ってくれ！","ENG":"Look! I found another survivor! Help me!","TWN":"喂！還有人在這裡！救命！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"해적과… 헌터…? 전부 여기로 휩쓸려온 건가?","JPN":"海賊と……ハンター……？　みんなここまで流されてきたのか？","ENG":"Pirates and... hunters...? Did we all get washed up here?","TWN":"海盜和…獵人…？大家全都被浪捲到這裡來嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그러고보니 드라코 선장은?","JPN":"そういえば、ドラコ船長は？","ENG":"Come to think of it, where's Captain Dracasia?","TWN":"話說回來，德拉克船長呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"저희가 깨어났을 땐 어디에도 보이지 않았습니다.","JPN":"俺たちが目を覚ました時には、どこにも見当たらなかったんです。","ENG":"When we woke up, we couldn't find her anywhere.","TWN":"我們醒來的時候就沒看到她。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"조류에 휩쓸린 배들이 해안가에서 뒤엉키는 바람에, 우리 배가 어딨는지도 모르겠어.","JPN":"潮流に流された船が海岸で重なり合って、俺たちの船がどこにあるのかもわからないんだよ。","ENG":"The tide pushed all the ships to the coast and... I can't tell which one's ours.","TWN":"我們被潮水推到岸邊，我們的船也不知道去哪裡了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"뭐, 무사할 테니 걱정 말자고요.","JPN":"まあ、無事でしょうから心配は無用ですね。","ENG":"Well, I guess she'll be all right. Let's not worry too much about her.","TWN":"別擔心，船長會沒事的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님은 보통 평범한 인간이 아니잖아요?","JPN":"船長は、普通の人間ではないでしょう？","ENG":"Our captain isn't an ordinary person, remember?","TWN":"船長可不是一般人！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"게다가 이것 좀 보세요!","JPN":"それに、これを見てください！","ENG":"And look at this!","TWN":"而且，你看這個！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그건…? 방금 내 입에서 나왔던…","JPN":"それは……？　さっきあたしの口から出た……","ENG":"That's...? Didn't I just spit that out...?","TWN":"這是…？這是剛剛從我嘴裡掉出來的…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"잠깐! 이거 금화잖아?!","JPN":"待て！　これ、金貨だろう！？","ENG":"Wait! That's a gold coin!","TWN":"等等！這是金幣？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"주위를 둘러보세요! 이런 게 이 모래사장에 잔뜩 널려있다고요!","JPN":"周りを見てください！　同じものが、この砂浜にいっぱいあります！","ENG":"Look around! These things are just scattered all across this beach!","TWN":"快看周圍！沙子上到處都是這種東西！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"…정말이군요. 금화뿐만 아니라 해안가가 온통 보물들입니다!","JPN":"……本当ですね。金貨だけじゃなく、全海岸が宝だらけです！","ENG":"...She's right. It's not just gold coins, but the whole coast is littered with treasure!","TWN":"…真的，不僅僅是金幣，沿岸到處都是寶藏！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"우오오옷! 정말이잖아!","JPN":"うおおおっ！　本当だ！","ENG":"WHAAAT?! She's right!","TWN":"哇喔喔！這是真的！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"별로 좋은 소식은 아니네.","JPN":"あまりいいことではないな。","ENG":"That's not good news.","TWN":"這可不是好消息。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"네? 왜요?","JPN":"え？　どうしてですか？","ENG":"Huh? Why not?","TWN":"嗯？為什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"사람이 너무 많거든.","JPN":"人が多すぎる。","ENG":"There are too many people here.","TWN":"太多人要分。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"여기 있는 모든 사람들이 공평함을 원하진 않을 테니까.","JPN":"ここにいるすべての人が、公平を求めてはいないはずだ。","ENG":"But no one here will want to divide the loot into equal shares.","TWN":"不是所有人都願意平分這些東西。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"어이! 방금 뭐라고 한 거냐? 앙?","JPN":"おい！　今何って言った！　ああん？","ENG":"Hey! What did you just say to me, huh?!","TWN":"喂？你剛剛說什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"해초가 귓구멍에도 박혔냐? 여기 있는 보물들은 우리가 먼저 발견했으니, 다른 데나 알아보라고.","JPN":"海藻が耳につまってんのか？　ここにある宝は俺らが先に見つけたんだ、他を当たれ。","ENG":"Did you get kelp in your ears?! We found this treasure first, so it's ours! Go find your own loot!","TWN":"海藻跑到你耳朵裡了嗎？這裡的寶藏是我們先找到的，你們去別的地方吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"그게 싫으면 여기서 한 판 붙던가.","JPN":"それが気に食わねーなら、ここで勝負するか。","ENG":"If you have a problem with that, then how about we settle it for good?","TWN":"不想走的話，就來打一架吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"케케케, 감히 해적을 도발하다니. 물고기밥으로 만들어주마!","JPN":"ケケケ、海賊を挑発するなんてよ。魚のエサにしてやる！","ENG":"Kekeke, you shouldn't mess with pirates, kiddo. I'll turn you into fish food!","TWN":"哈哈哈，你竟敢挑釁海盜，我要讓你吃不完兜著走！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"아, 좋지! 해적놈들을 전부 쓸어버리면 보물을 나누기도 훨씬 편해지겠구만!","JPN":"はっ、いいだろう！　海賊を全部片付けちまえば、宝を分けるのも楽になりそうだ！","ENG":"Sound great! More to go around once we get rid of all the pirates!","TWN":"喔，很好！等我們把所有的海盜都除掉再來分寶藏會容易很多！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 서로 협력하기로 한지 얼마나 됐다고 벌써 싸우는 건데?","JPN":"な、何だ？　互いに協力するって言ったばかりなのに、もうケンカしてるのか？","ENG":"W-what? They're already fighting after agreeing to work together?","TWN":"搞什麼？他們剛剛還在並肩作戰，這麼快就又要打起來啦？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_NEWBIE","text":{"KOREA":"말려야 하는 거 아닐까요?!","JPN":"止めた方がいいんじゃないですか！？","ENG":"Shouldn't we stop them?!","TWN":"我們是不是該去阻止一下？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"소용없어.","JPN":"無駄だ。","ENG":"It's no use.","TWN":"沒有用的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"본능이 이성을 지배하기 시작한 이상, 무슨 말도 통하지 않을 거야.","JPN":"本能が理性を支配し始めた以上、何を言っても通じないよ。","ENG":"Once instinct dominates rationality, no words can calm them down.","TWN":"人一旦被本能控制，說什麼都沒用。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그리고 넌 대포에 불 붙이지 마, 탈리.","JPN":"それに、タリー、あなたは大砲に火をつけるな。","ENG":"Also, don't start lighting up your cannon, Tallie.","TWN":"塔莉，放下你的大砲。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그, 그치만 다들 눈이 뒤집혀서 싸우고 있는 걸요! 저도 쏠래요!","JPN":"で、でもみなさんが理性を失って戦っているではないですか！　私も撃ちますわ！","ENG":"B-but they're all fighting! I wanna shoot something too!","TWN":"可是，他們打得很激烈呢！我也想加入！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"애초에 넌 보물을 갖고 싶은 게 아니라 그냥 대포가 쏘고 싶을 뿐이잖아.","JPN":"そもそもあなたは宝が欲しいわけじゃなくて、ただ大砲が撃ちたいだけだろう。","ENG":"You're here just because you want to shoot your cannon, unlike most of them who are here for the treasure.","TWN":"你只是想發射大砲吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"나중을 위해서라도 포탄은 아껴둬.","JPN":"今後のためにも、砲弾は節約しておけ。","ENG":"Save your ammo for later.","TWN":"砲彈省著點，以後還要用。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"히잉-","JPN":"ふえん～","ENG":"Hnnnggg…","TWN":"哼哼。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"저길 봐! 저쪽에도 해적이 있다!","JPN":"あっちを見ろ！　あそこにも海賊がいるぞ！","ENG":"Look! There are pirates over there too!","TWN":"快看！那邊也有海盜！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"우왓! 잠깐만!","JPN":"うわっ！　ちょっと待って！","ENG":"Whoa! Wait a sec!","TWN":"哇！等等！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"우린 보물에 하나도 관심 없어! 싸우려면 너희끼리 싸우라고!","JPN":"俺たちは宝なんかに興味はない！　戦いたいならお前たちだけでやれよ！","ENG":"We're not interested in the treasure! If you're gonna fight, count us out!","TWN":"我們才不要寶藏！要打，你們自己去打！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"헛소리!","JPN":"戯言を！","ENG":"Don't give us that crap!","TWN":"騙鬼啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"끼야아악!!","JPN":"きゃああっ！！","ENG":"Kyaaaah!!","TWN":"啊啊啊啊！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"앗! 소냐~ 저쪽에서 총을 쏘는데요? 어쩌면 좋을까요?","JPN":"あっ！　ソーニャ～あちらから銃を撃ってきますよ？　どうしましょう？","ENG":"Oh! Sonya! They're shooting at us! What should we do?","TWN":"索妮雅～他們向我們開槍欸，我們該怎麼辦呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀…"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"너무 한복판으로 뛰어들지만 마. 기회를 봐서 빠질 수 있게.","JPN":"あまり中まで飛び込んでいくな。チャンスを見て抜け出せるように。","ENG":"Just stay on the sidelines so we can slip out at the proper time.","TWN":"不要太投入其中，看准機會就撤退。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"네에-!","JPN":"はーい！","ENG":"Okay-!","TWN":"好喔！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우와아악! 포탄이다!","JPN":"うわああっ！　砲弾だ！","ENG":"Watch out! Cannon ball!","TWN":"啊啊啊啊！有砲彈！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L41_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"꺄하하핫!!!","JPN":"キャハハハッ！！！","ENG":"KYAHAHAHA!!!","TWN":"哈哈哈哈！！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};